export function createCart() {
  const items = [];
  return {
    add(name, price, qty) {
      items.push({ name, price, qty });
    },
    remove(name) {
      const index = items.findIndex((it) => it.name === name);
      items.splice(index, 1);
    },
    total() {
      return items.reduce((sum, it) => sum + it.price * it.qty, 0);
    },
    count() {
      return items.length;
    }
  };
}

import assert from 'node:assert/strict';
import { test } from 'node:test';
import { createCart } from './src/shopping-cart.js';

test('adding the same item merges quantity', () => {
  const c = createCart();
  c.add('apple', 2, 1);
  c.add('apple', 2, 3);
  assert.equal(c.count(), 1);
  assert.equal(c.total(), 8);
});
test('removing an unknown item leaves others intact', () => {
  const c = createCart();
  c.add('apple', 2, 1);
  c.remove('banana');
  assert.equal(c.count(), 1);
});
test('total sums price times quantity', () => {
  const c = createCart();
  c.add('apple', 2, 3);
  assert.equal(c.total(), 6);
});
test('removing an existing item works', () => {
  const c = createCart();
  c.add('apple', 1, 1);
  c.add('banana', 2, 1);
  c.remove('apple');
  assert.equal(c.count(), 1);
});
